# 输入获取
rows, cols = list(map(int, input().split()))
table = [input().split() for _ in range(rows)]
start, end = input().split(":")


# 判断一个内容是否为单元格坐标
def isPos(pos):
    return "Z" >= pos[0] >= 'A'


# 解析单元格坐标  为  矩阵坐标
def getPos(pos):
    c = ord(pos[0]) - 65
    r = int(pos[1:]) - 1
    return r, c


# 获取矩阵对应坐标的值,并且更新矩阵对应单元格的内容
def getPosVal(pos):
    r, c = pos
    table[r][c] = getCellVal(table[r][c])
    return table[r][c]


# 双目运算
def operate(ops, isAdd):
    op1 = 0
    op2 = 0

    if isPos(ops[0]):
        # 如果操作数1是单元格
        op1 = getPosVal(getPos(ops[0]))
    else:
        # 如果操作数1是数字
        op1 = int(ops[0])

    if isPos(ops[1]):
        op2 = getPosVal(getPos(ops[1]))
    else:
        op2 = int(ops[1])

    if isAdd:
        return op1 + op2
    else:
        return op1 - op2


# 获取单元格的值
def getCellVal(cell):
    cell = str(cell)
    # 单元格内容cell如果以'='开头,则必然是公式
    if cell[0] == "=":
        # fn是公式内容
        fn = cell[1:]

        # 如果公式内容fn包含“+”,则可能是两个单元格的双目运算,也可能是单元格和数字的双目运算
        if fn.find("+") != -1:
            return operate(fn.split("+"), True)
        # 如果公式内容fn包含“-”,则可能是两个单元格的双目运算,也可能是单元格和数字的双目运算
        elif fn.find("-") != -1:
            return operate(fn.split("-"), False)
        # 如果公式内容fn不包含“+”和“-”,则必然等于某单元格的值,例如=B12
        else:
            return getPosVal(getPos(fn))
    # 单元格内容cell如果不以'='开头,则必然是数字,且是非负正数
    else:
        return int(cell)


# 算法入口
def getResult():
    r1, c1 = getPos(start)
    r2, c2 = getPos(end)

    ans = 0
    for i in range(r1, r2 + 1):
        for j in range(c1, c2 + 1):
            ans += getCellVal(table[i][j])

    return ans


# 算法调用
print(getResult())
